def prove_mpjao3dan(sys: System) -> Proof:
    """Eliminate a three-way disjunction in a deduction.  (Contributed by
    Thierry Arnoux, 13-Apr-2018.)  (Proof shortened by Wolf Lammen,
    20-Apr-2024.)
    """
    lb = ProofBuilder(sys, "mpjao3dan")
    h1 = lb.hyp("mpjao3dan.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("mpjao3dan.2", "( ( φ ∧ θ ) → χ )")
    h3 = lb.hyp("mpjao3dan.3", "( ( φ ∧ τ ) → χ )")
    h4 = lb.hyp("mpjao3dan.4", "( φ → ( ψ ∨ θ ∨ τ ) )")
    s1 = lb.ref("s1", "( ( φ ∧ ( ψ ∨ θ ∨ τ ) ) → χ )", h1, h2, h3, ref="3jaodan", note="3jaodan")
    res = lb.ref("res", "( φ → χ )", h4, s1, ref="mpdan", note="mpdan")
    return lb.build(res)

def prove_3jaao(sys: System) -> Proof:
    """Inference conjoining and disjoining the antecedents of three
    implications.  (Contributed by Jeff Hankins, 15-Aug-2009.)  (Proof
    shortened by Andrew Salmon, 13-May-2011.)  (Proof shortened by Garrett
    Katz, 16-Jun-2026.)
    """
    lb = ProofBuilder(sys, "3jaao")
    h1 = lb.hyp("3jaao.1", "( φ → ( ψ → χ ) )")
    h2 = lb.hyp("3jaao.2", "( θ → ( τ → χ ) )")
    h3 = lb.hyp("3jaao.3", "( η → ( ζ → χ ) )")
    s1 = lb.ref("s1", "( ( ( ψ → χ ) ∧ ( τ → χ ) ∧ ( ζ → χ ) ) → ( ( ψ ∨ τ ∨ ζ ) → χ ) )", ref="3jao", note="3jao")
    res = lb.ref("res", "( ( φ ∧ θ ∧ η ) → ( ( ψ ∨ τ ∨ ζ ) → χ ) )", h1, h2, h3, s1, ref="syl3an", note="syl3an")
    return lb.build(res)

