def prove_syl3an9b(sys: System) -> Proof:
    """Nested syllogism inference conjoining 3 dissimilar antecedents.
    (Contributed by NM, 1-May-1995.)
    """
    lb = ProofBuilder(sys, "syl3an9b")
    h1 = lb.hyp("syl3an9b.1", "( φ → ( ψ ↔ χ ) )")
    h2 = lb.hyp("syl3an9b.2", "( θ → ( χ ↔ τ ) )")
    h3 = lb.hyp("syl3an9b.3", "( η → ( τ ↔ ζ ) )")
    s1 = lb.ref("s1", "( ( φ ∧ θ ) → ( ψ ↔ τ ) )", h1, h2, ref="sylan9bb", note="sylan9bb")
    s2 = lb.ref("s2", "( ( ( φ ∧ θ ) ∧ η ) → ( ψ ↔ ζ ) )", s1, h3, ref="sylan9bb", note="sylan9bb")
    res = lb.ref("res", "( ( φ ∧ θ ∧ η ) → ( ψ ↔ ζ ) )", s2, ref="3impa", note="3impa")
    return lb.build(res)

