    s2 = lb.ref("s2", "( φ → ( ( ( ψ ∨ θ ) ∨ η ) ↔ ( ( χ ∨ τ ) ∨ ζ ) ) )", s1, h3, ref="orbi12d", note="orbi12d")
    s3 = lb.ref("s3", "( ( ψ ∨ θ ∨ η ) ↔ ( ( ψ ∨ θ ) ∨ η ) )", ref="df-3or", note="df-3or")
    s4 = lb.ref("s4", "( ( χ ∨ τ ∨ ζ ) ↔ ( ( χ ∨ τ ) ∨ ζ ) )", ref="df-3or", note="df-3or")
    res = lb.ref("res", "( φ → ( ( ψ ∨ θ ∨ η ) ↔ ( χ ∨ τ ∨ ζ ) ) )", s2, s3, s4, ref="3bitr4g", note="3bitr4g")
    return lb.build(res)

