def prove_an6(sys: System) -> Proof:
    """Rearrangement of 6 conjuncts.  (Contributed by NM, 13-Mar-1995.)"""
    lb = ProofBuilder(sys, "an6")
    s1 = lb.ref("s1", "( ( ( ( φ ∧ ψ ) ∧ χ ) ∧ ( ( θ ∧ τ ) ∧ η ) ) ↔ ( ( ( φ ∧ ψ ) ∧ ( θ ∧ τ ) ) ∧ ( χ ∧ η ) ) )", ref="an4", note="an4")
    s2 = lb.ref("s2", "( ( ( φ ∧ ψ ) ∧ ( θ ∧ τ ) ) ↔ ( ( φ ∧ θ ) ∧ ( ψ ∧ τ ) ) )", ref="an4", note="an4")
    s3 = lb.ref("s3", "( ( ( ( φ ∧ ψ ) ∧ χ ) ∧ ( ( θ ∧ τ ) ∧ η ) ) ↔ ( ( ( φ ∧ θ ) ∧ ( ψ ∧ τ ) ) ∧ ( χ ∧ η ) ) )", s1, s2, ref="bianbi", note="bianbi")
    s4 = lb.ref("s4", "( ( φ ∧ ψ ∧ χ ) ↔ ( ( φ ∧ ψ ) ∧ χ ) )", ref="df-3an", note="df-3an")
    s5 = lb.ref("s5", "( ( θ ∧ τ ∧ η ) ↔ ( ( θ ∧ τ ) ∧ η ) )", ref="df-3an", note="df-3an")
