def prove_3pm3_2ni(sys: System) -> Proof:
    """Triple negated disjunction introduction.  (Contributed by Scott Fenton,
    20-Apr-2011.)
    """
    lb = ProofBuilder(sys, "3pm3.2ni")
    h1 = lb.hyp("3pm3.2ni.1", "¬ φ")
    h2 = lb.hyp("3pm3.2ni.2", "¬ ψ")
    h3 = lb.hyp("3pm3.2ni.3", "¬ χ")
    s1 = lb.ref("s1", "¬ ( φ ∨ ψ )", h1, h2, ref="pm3.2ni", note="pm3.2ni")
    s2 = lb.ref("s2", "¬ ( ( φ ∨ ψ ) ∨ χ )", s1, h3, ref="pm3.2ni", note="pm3.2ni")
    s3 = lb.ref("s3", "( ( φ ∨ ψ ∨ χ ) ↔ ( ( φ ∨ ψ ) ∨ χ ) )", ref="df-3or", note="df-3or")
    res = lb.ref("res", "¬ ( φ ∨ ψ ∨ χ )", s2, s3, ref="mtbir", note="mtbir")
    return lb.build(res)

def prove_an42ds(sys: System) -> Proof:
    """Inference exchanging the last antecedent with the second one.  See also
    ~ an32s .  (Contributed by Thierry Arnoux, 3-Jun-2025.)
    """
    lb = ProofBuilder(sys, "an42ds")
    h1 = lb.hyp("an42ds.1", "( ( ( ( φ ∧ ψ ) ∧ χ ) ∧ θ ) → τ )")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) ∧ θ ) ↔ ( ( φ ∧ θ ) ∧ ψ ) )", ref="an32", note="an32")
    s2 = lb.ref("s2", "( ( ( ( φ ∧ ψ ) ∧ θ ) ∧ χ ) ↔ ( ( ( φ ∧ θ ) ∧ ψ ) ∧ χ ) )", s1, ref="anbi1i", note="anbi1i")
    s3 = lb.ref("s3", "( ( ( ( φ ∧ ψ ) ∧ θ ) ∧ χ ) ↔ ( ( ( φ ∧ ψ ) ∧ χ ) ∧ θ ) )", ref="an32", note="an32")
    s4 = lb.ref("s4", "( ( ( ( φ ∧ θ ) ∧ ψ ) ∧ χ ) ↔ ( ( ( φ ∧ θ ) ∧ χ ) ∧ ψ ) )", ref="an32", note="an32")
    s5 = lb.ref("s5", "( ( ( ( φ ∧ ψ ) ∧ χ ) ∧ θ ) ↔ ( ( ( φ ∧ θ ) ∧ χ ) ∧ ψ ) )", s2, s3, s4, ref="3bitr3i", note="3bitr3i")
    res = lb.ref("res", "( ( ( ( φ ∧ θ ) ∧ χ ) ∧ ψ ) → τ )", s5, h1, ref="sylbir", note="sylbir")
    return lb.build(res)


